public class AllPrimitives {
    public static void main(String[] args) {
        // Integer types (whole numbers)
        byte tinyNum = 100;           // -128 to 127
        short smallNum = 30000;       // -32,768 to 32,767
        int normalNum = 2000000000;   // ~-2.1B to ~2.1B
        long hugeNum = 9000000000L;   // note the 'L'!

        // Floating-point types (decimals)
        float singlePrec = 3.14f;     // note the 'f'!
        double doublePrec = 3.14159265358979;

        // Character type
        char letter = 'A';

        // Boolean type
        boolean isJavaFun = true;

        // Print them all
        System.out.println("byte:    " + tinyNum);
        System.out.println("short:   " + smallNum);
        System.out.println("int:     " + normalNum);
        System.out.println("long:    " + hugeNum);
        System.out.println("float:   " + singlePrec);
        System.out.println("double:  " + doublePrec);
        System.out.println("char:    " + letter);
        System.out.println("boolean: " + isJavaFun);
    }
}

