public class TypeCasting {
    public static void main(String[] args) {
        System.out.println("=== WIDENING (safe, automatic) ===");
        int myInt = 42;
        double myDouble = myInt;  // int -> double (safe)
        System.out.println("int 42 -> double: " + myDouble);

        byte myByte = 100;
        int fromByte = myByte;  // byte -> int (safe)
        System.out.println("byte 100 -> int: " + fromByte);

        System.out.println();
        System.out.println("=== NARROWING (risky, manual cast) ===");
        double price = 9.99;
        int truncated = (int) price;  // LOSES .99!
        System.out.println("double 9.99 -> int: " + truncated);

        double big = 9999.99;
        int bigTrunc = (int) big;
        System.out.println("double 9999.99 -> int: " + bigTrunc);

        System.out.println();
        System.out.println("=== DANGEROUS NARROWING ===");
        int tooBig = 130;
        byte overflow = (byte) tooBig;  // 130 > 127!
        System.out.println("int 130 -> byte: " + overflow + " (OVERFLOW!)");

        int wayTooBig = 1000;
        byte badCast = (byte) wayTooBig;
        System.out.println("int 1000 -> byte: " + badCast + " (OVERFLOW!)");
    }
}

public class OverflowDemo {
    public static void main(String[] args) {
        System.out.println("=== INTEGER OVERFLOW ===");
        int max = Integer.MAX_VALUE;  // 2,147,483,647
        System.out.println("Max int value:   " + max);
        System.out.println("Max + 1:         " + (max + 1));
        System.out.println("Max + 2:         " + (max + 2));

        System.out.println();
        int min = Integer.MIN_VALUE;  // -2,147,483,648
        System.out.println("Min int value:   " + min);
        System.out.println("Min - 1:         " + (min - 1));

        System.out.println();
        System.out.println("=== REAL-WORLD DANGER ===");
        int itemPrice = 50;  // dollars
        int quantity = 50000000;  // 50 million items
        int totalCost = itemPrice * quantity;  // OVERFLOW!
        System.out.println("50 * 50,000,000 = " + totalCost);
        System.out.println("Expected: 2,500,000,000 (exceeds int max!)");

        // THE FIX: use long!
        long safeCost = (long) itemPrice * quantity;
        System.out.println("Using long: " + safeCost + " (correct!)");
    }
}

