public class MixedArithmetic {
    public static void main(String[] args) {
        System.out.println("=== INTEGER DIVISION ===");
        int a = 7;
        int b = 2;
        System.out.println("7 / 2 = " + (a / b));    // 3 (not 3.5!)
        System.out.println("7 % 2 = " + (a % b));    // 1 (remainder)

        System.out.println();
        System.out.println("=== GETTING DECIMAL RESULTS ===");
        double result1 = 7.0 / 2;        // one double -> result is double
        double result2 = (double) 7 / 2;  // cast to double first
        double result3 = 7 / 2;          // TRAP: int division, THEN stored as double
        System.out.println("7.0 / 2 = " + result1);    // 3.5
        System.out.println("(double)7 / 2 = " + result2); // 3.5
        System.out.println("7 / 2 (as double) = " + result3); // 3.0 !

        System.out.println();
        System.out.println("=== TYPE PROMOTION ===");
        byte x = 10;
        byte y = 20;
        // byte sum = x + y;  // ERROR! Result is promoted to int
        int sum = x + y;      // Correct
        System.out.println("byte + byte = int: " + sum);
    }
}

public class FloatingPointTrap {
    public static void main(String[] args) {
        System.out.println("=== THE 0.1 + 0.2 PROBLEM ===");
        double sum = 0.1 + 0.2;
        System.out.println("0.1 + 0.2 = " + sum);
        System.out.println("0.1 + 0.2 == 0.3? " + (sum == 0.3));

        System.out.println();
        System.out.println("=== MORE PRECISION ISSUES ===");
        double tenth = 0.1;
        double result = 0.0;
        for (int i = 0; i < 10; i++) {
            result += tenth;
        }
        System.out.println("0.1 added 10 times = " + result);
        System.out.println("Should be 1.0? " + (result == 1.0));

        System.out.println();
        System.out.println("=== THE SAFE WAY TO COMPARE ===");
        double a = 0.1 + 0.2;
        double b = 0.3;
        double epsilon = 0.0001;  // acceptable margin of error
        boolean closeEnough = Math.abs(a - b) < epsilon;
        System.out.println("Close enough? " + closeEnough);
    }
}

public class GradeCalculator {
    public static void main(String[] args) {
        // Student data (using appropriate types)
        String studentName = "Alex";
        int studentId = 20251001;

        // Test scores (using double for precision)
        double test1 = 85.5;
        double test2 = 92.0;
        double test3 = 78.5;
        double test4 = 88.0;

        // Constants
        final int NUM_TESTS = 4;
        final double PASS_THRESHOLD = 60.0;

        // Calculate average
        double total = test1 + test2 + test3 + test4;
        double average = total / NUM_TESTS;

        // Determine pass/fail
        boolean passed = average >= PASS_THRESHOLD;

        // Determine grade letter
        char grade;
        if (average >= 90) grade = 'A';
        else if (average >= 80) grade = 'B';
        else if (average >= 70) grade = 'C';
        else if (average >= 60) grade = 'D';
        else grade = 'F';

        // Display report
        System.out.println("=============================");
        System.out.println("  STUDENT GRADE REPORT");
        System.out.println("=============================");
        System.out.printf("Student: %s (ID: %d)%n", studentName, studentId);
        System.out.printf("Tests: %.1f, %.1f, %.1f, %.1f%n", test1, test2, test3, test4);
        System.out.printf("Average: %.2f%n", average);
        System.out.printf("Grade: %c%n", grade);
        System.out.printf("Status: %s%n", passed ? "PASSED" : "FAILED");
        System.out.println("=============================");
    }
}

public class IntegerTypes {
    public static void main(String[] args) {
        // BYTE: -128 to 127. Good for small numbers, saving memory
        byte dayOfMonth = 25;
        byte percentage = 100;  // max is 127, careful!
        System.out.println("Day: " + dayOfMonth + ", Percentage: " + percentage);
        System.out.println("Byte range: " + Byte.MIN_VALUE + " to " + Byte.MAX_VALUE);

        System.out.println();

        // SHORT: -32,768 to 32,767. Rarely used.
        short year = 2025;
        short portNumber = 8080;
        System.out.println("Year: " + year + ", Port: " + portNumber);
        System.out.println("Short range: " + Short.MIN_VALUE + " to " + Short.MAX_VALUE);

        System.out.println();

        // LONG: ~-9.2 quintillion to ~9.2 quintillion
        long worldPopulation = 8000000000L;  // 8 billion needs long!
        long fileSize = 4294967296L;         // 4GB in bytes needs long!
        long timestamp = System.currentTimeMillis();
        System.out.println("World population: " + worldPopulation);
        System.out.println("File size (bytes): " + fileSize);
        System.out.println("Timestamp (ms): " + timestamp);
        System.out.println("Long range: " + Long.MIN_VALUE + " to " + Long.MAX_VALUE);
    }
}

public class CharMagic {
    public static void main(String[] args) {
        // Characters are secretly numbers!
        char letter = 'A';
        System.out.println("Character: " + letter);
        System.out.println("Unicode value: " + (int) letter);

        System.out.println();

        // Character arithmetic
        char nextLetter = (char) (letter + 1);
        System.out.println("A + 1 = " + nextLetter);  // B

        // Print the alphabet!
        System.out.print("Alphabet: ");
        for (char c = 'A'; c <= 'Z'; c++) {
            System.out.print(c + " ");
        }
        System.out.println();

        // Digit characters vs actual numbers
        char digitChar = '7';
        int digitValue = digitChar - '0';  // convert char to number
        System.out.println("\nChar '7' unicode: " + (int) digitChar); // 55
        System.out.println("Actual value: " + digitValue);           // 7

        // Special characters
        System.out.println("\nSpecial chars:");
        System.out.println("Space: '" + ' ' + "' = " + (int) ' ');  // 32
        System.out.println("Zero:  '" + '0' + "' = " + (int) '0');  // 48
        System.out.println("At:    '" + '@' + "' = " + (int) '@');  // 64
    }
}

public class DataTypeSecurity {
    public static void main(String[] args) {
        System.out.println("=== SECURITY: DATA TYPE VULNERABILITIES ===");
        System.out.println();

        // VULNERABILITY 1: Integer overflow in size check
        System.out.println("[VULN 1] Integer Overflow in Validation");
        int maxAllowed = 100;
        int requested = Integer.MAX_VALUE;  // attacker sends huge number
        int extra = 5;
        int totalNeeded = requested + extra;  // OVERFLOW! Goes negative
        System.out.println("Requested: " + requested);
        System.out.println("Total needed: " + totalNeeded);
        System.out.println("totalNeeded < maxAllowed? " + (totalNeeded < maxAllowed));
        System.out.println("DANGER: Validation bypassed!\n");

        // VULNERABILITY 2: Truncation in type conversion
        System.out.println("[VULN 2] Numeric Truncation (CWE-197)");
        int largeAmount = 256;
        byte truncated = (byte) largeAmount;  // silently becomes 0!
        System.out.println("Original amount: " + largeAmount);
        System.out.println("After byte cast: " + truncated);
        System.out.println("DANGER: 256 became 0 silently!\n");

        // VULNERABILITY 3: Float precision in money
        System.out.println("[VULN 3] Float Precision Loss");
        float balance = 10000000.0f;  // 10 million
        float deposit = 1.0f;
        float newBalance = balance + deposit;
        System.out.println("Balance: " + balance);
        System.out.println("+ Deposit: " + deposit);
        System.out.println("New balance: " + newBalance);
        System.out.println("DANGER: The deposit DISAPPEARED!\n");

        // THE FIX
        System.out.println("=== SAFE ALTERNATIVES ===");
        System.out.println("1. Use long for large calculations");
        System.out.println("2. Check ranges before casting");
        System.out.println("3. Use double (not float) for money");
        System.out.println("4. Use BigDecimal for critical finance");
    }
}

